mapper.select:

where c.tenant_id = #{tenantId} and c.object_type = #{objectType}
  and c.object_id = #{objectId} and c.metric_definition_id = #{metricDefinitionId}
  and c.parameter_signature = #{parameterSignature}

mapper.update:
update fp_resource_metric_config
set task_status = 'RUNNING', updated_at = #{now}
where tenant_id = #{tenantId}
  and id = #{id}
  and enabled = true
  and next_collect_at is not null
  and next_collect_at <= #{now}
  and task_status != 'RUNNING'

update fp_resource_metric_config
set task_status = #{taskStatus}, last_collect_status = #{lastCollectStatus},
    last_collect_message = #{lastCollectMessage}, last_collect_at = #{lastCollectAt},
    next_collect_at = #{nextCollectAt}, updated_at = #{updatedAt}
where tenant_id = #{tenantId} and id = #{id}
